# ==============================================================================
# Most viruses and malware hide in attachments.
# Mostly hidden in invoices, orders and other business-related data.
# The documents are usually sent as archive files.
#
# Rspamd already searches for unwanted file extensions.
# Here we supplement the file with other combinations.
#
# ------------------------------------------------------------------------------
# Language: -
# Weight:   12.0
# ==============================================================================

# Extensions
# ------------------------------------------------------------------------------
/\.001$/i
/\.arj$/i
/\.bz2$/i
/\.do$/i
/\.jar$/i
/\.js$/i
/\.lha$/i
/\.library-ms$/i
/\.shtml$/i
/\.tbz$/i
/\.uue$/i

/\.r00$/i
/\.r09$/i
/\.r10$/i
/\.r11$/i
/\.r15$/i
/\.r16$/i
/\.r18$/i

/\.dhtml$/i
/\.smtml$/i

# Special
/\.\.docx/i
/\.xlsx?_/i

# 30.03 26 - We're now blocking html files. A few banking institutions send secure messages as html attachments.
# 25.06.26 - Exception: allow incamail.html
/^(?!incamail\.html?$).+\.html?$/i
/^(?!secure-email\.html?$).+\.html?$/i

# Double Extension
# ------------------------------------------------------------------------------
/\.docx\.z$/i
/\.img\.gz/i
/\.pdf\.rar/i

/\.(jpg|pdf|xlsx|xlx|xml)\.(lz|t?gz|zip)/i

/\.xlxs\.(ehe ?|lz|t?gz|zip)/i

/xlsxr?\.tar/i
/pdf\.z$/i

/\.(docx|rar|zip)\.txt$/i

# Pseudo Double Extension
# ------------------------------------------------------------------------------
/(,|_|-)(doc|pdf)\.(docx|gz|rar|svg|tar|zip)/i

# Sample: pdf (4kb).docx
/pdf.?\(\d{1,5}kb\).?\.docx/i

# Triple Extension
# ------------------------------------------------------------------------------
/\.xls\.tar\.gz/i
